const payload = $input.first().json;
const headers = $input.first().json.headers || {};

// GitHub event tipini belirle
const eventType = headers['x-github-event'] || 'unknown';

let embed = {
  color: 0x238636,
  timestamp: new Date().toISOString(),
  footer: { text: '🤖 n8n GitHub Monitor' }
};

switch(eventType) {
  case 'push':
    const commits = payload.body?.commits || payload.commits || [];
    const pusher = payload.body?.pusher?.name || payload.pusher?.name || 'Bilinmiyor';
    const repo = payload.body?.repository?.full_name || payload.repository?.full_name || 'Bilinmiyor';
    const branch = (payload.body?.ref || payload.ref || '').replace('refs/heads/', '');

    let commitList = '';
    commits.slice(0, 5).forEach((c, i) => {
      const shortHash = (c.id || '').substring(0, 7);
      commitList += `\`${shortHash}\` ${c.message || 'Mesaj yok'}\n`;
    });
    if (commits.length > 5) commitList += `...ve ${commits.length - 5} commit daha`;

    embed.title = `🚀 Yeni Push: ${repo}`;
    embed.description = `**Branch:** \`${branch}\`\n**Pusher:** ${pusher}\n**Commit Sayısı:** ${commits.length}\n\n${commitList}`;
    embed.color = 0x238636;
    break;

  case 'pull_request':
    const pr = payload.body?.pull_request || payload.pull_request || {};
    const action = payload.body?.action || payload.action || '';

    const actionEmoji = {
      'opened': '🆕',
      'closed': pr.merged ? '🟣' : '❌',
      'merged': '🟣',
      'reopened': '🔄',
      'review_requested': '👀'
    };

    embed.title = `${actionEmoji[action] || '📋'} PR ${action}: ${pr.title || 'Başlıksız'}`;
    embed.description = `**Repo:** ${payload.body?.repository?.full_name || payload.repository?.full_name || ''}\n**Yazan:** ${pr.user?.login || 'Bilinmiyor'}\n**Branch:** \`${pr.head?.ref || ''}\` → \`${pr.base?.ref || ''}\`\n\n${(pr.body || '').substring(0, 200)}`;
    embed.url = pr.html_url || '';
    embed.color = action === 'opened' ? 0x238636 : action === 'closed' ? 0xda3633 : 0x8957e5;
    break;

  case 'issues':
    const issue = payload.body?.issue || payload.issue || {};
    const issueAction = payload.body?.action || payload.action || '';

    embed.title = `🐛 Issue ${issueAction}: ${issue.title || 'Başlıksız'}`;
    embed.description = `**Repo:** ${payload.body?.repository?.full_name || payload.repository?.full_name || ''}\n**Yazan:** ${issue.user?.login || 'Bilinmiyor'}\n**Labels:** ${(issue.labels || []).map(l => l.name).join(', ') || 'Yok'}\n\n${(issue.body || '').substring(0, 200)}`;
    embed.url = issue.html_url || '';
    embed.color = 0xd29922;
    break;

  default:
    embed.title = `📌 GitHub Event: ${eventType}`;
    embed.description = 'Bilinmeyen event tipi alındı.';
    embed.color = 0x848d97;
}

return [{ json: { embed } }];
